function kY(t) {
	const e = t || {};
	return String(e?.data?.name || e?.name || e?.message?.name || e?.message || "").trim();
}
async function Bd(t) {
	if (!t.ok) {
		let e = `HTTP ${t.status}`;
		try {
			const n = await t.json();
			if (typeof n?.message == "string") e = n.message;
			else if (typeof n?._server_messages == "string")
				try {
					const r = JSON.parse(n._server_messages);
					Array.isArray(r) && r.length && (e = JSON.parse(r[0])?.message || e);
				} catch {}
		} catch {}
		throw new Error(e);
	}
	try {
		return await t.json();
	} catch {
		return null;
	}
}
